/**
 * Подтема PlasmaHomeDsTheme.Inverse
 */
@Composable
public fun PlasmaHomeDsTheme.Inverse(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalPlasmaHomeDsColors.current
    val overrideColors = currentColors.copyAttrs(InverseColorsOverride)
    val currentGradients = LocalPlasmaHomeDsGradients.current
    val overrideGradients = currentGradients.copyAttrs(InverseGradientsOverride)
    PlasmaHomeDsTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
